def _build_nx_graph(graph: SiteGraph) -> nx.DiGraph:
    """Convert SiteGraph to a networkx DiGraph."""
    G = nx.DiGraph()
    for node_id in graph.nodes:
        G.add_node(node_id)
    for edge in graph.edges:
        G.add_edge(edge.source, edge.target)
    return G

def _find_auth_violations(graph: SiteGraph) -> list[AuthBoundaryViolation]:
    """Find pages that should require auth but are accessible anonymously."""
    violations: list[AuthBoundaryViolation] = []
    for node in graph.nodes.values():
        if not node.requires_auth:
            continue
        # Check if any anonymous capture returned HTTP 200
        for capture in node.captures:
            if (
                capture.auth_context == AuthContext.anonymous
                and capture.http_status is not None
                and 200 <= capture.http_status < 300
            ):
                violations.append(AuthBoundaryViolation(
                    url=node.id,
                    expected_auth=True,
                    actual_accessible_anonymous=True,
                    evidence=f"Anonymous access returned HTTP {capture.http_status}",
                ))
                break
    return violations

def _find_timing_outliers(graph: SiteGraph) -> list[TimingOutlier]:
    """Find nodes with timing significantly above the mean (z-score > 2)."""
    metrics_by_name: dict[str, list[tuple[str, AuthContext, float]]] = {}

    for node in graph.nodes.values():
        for capture in node.captures:
            if capture.timing and capture.timing.duration_ms > 0:
                metrics_by_name.setdefault("duration_ms", []).append(
                    (node.id, capture.auth_context, capture.timing.duration_ms)
                )
            if capture.timing and capture.timing.ttfb_ms is not None and capture.timing.ttfb_ms > 0:
                metrics_by_name.setdefault("ttfb_ms", []).append(
                    (node.id, capture.auth_context, capture.timing.ttfb_ms)
                )
            if capture.dom_content_loaded_ms is not None and capture.dom_content_loaded_ms > 0:
                metrics_by_name.setdefault("dom_content_loaded_ms", []).append(
                    (node.id, capture.auth_context, capture.dom_content_loaded_ms)
                )
            if capture.load_event_ms is not None and capture.load_event_ms > 0:
                metrics_by_name.setdefault("load_event_ms", []).append(
                    (node.id, capture.auth_context, capture.load_event_ms)
                )

    outliers: list[TimingOutlier] = []
    for metric_name, values in metrics_by_name.items():
        if len(values) < 3:
            continue
        nums = [v[2] for v in values]
        mean = sum(nums) / len(nums)
        variance = sum((x - mean) ** 2 for x in nums) / len(nums)
        stddev = math.sqrt(variance)
        if stddev == 0:
            continue
        for url, auth_ctx, val in values:
            z = (val - mean) / stddev
            if abs(z) > 2.0:
                outliers.append(TimingOutlier(
                    url=url,
                    auth_context=auth_ctx,
                    metric=metric_name,
                    value_ms=val,
                    mean_ms=mean,
                    stddev_ms=stddev,
                    z_score=z,
                ))
    return outliers

def _enumerate_prime_paths(G: nx.DiGraph, max_loop: int = 2, max_paths: int = 1000) -> list[PrimePath]:
    """Enumerate prime paths: maximal simple paths with bounded loop traversal.

    A prime path is a simple path that is not a proper subpath of any other simple path.
    We bound loop iterations to max_loop to avoid combinatorial explosion.
    """
    paths: list[PrimePath] = []
    if G.number_of_nodes() == 0:
        return paths

    # For tractability, enumerate all simple paths between all pairs up to a cutoff
    cutoff = min(G.number_of_nodes(), 15)  # Cap path length for large graphs

    seen: set[tuple[str, ...]] = set()
    for source in G.nodes:
        for target in G.nodes:
            try:
                for path in nx.all_simple_paths(G, source, target, cutoff=cutoff):
                    path_tuple = tuple(path)
                    if len(path_tuple) < 2:
                        continue
                    if path_tuple in seen:
                        continue
                    seen.add(path_tuple)
                    paths.append(PrimePath(
                        path=list(path_tuple),
                        length=len(path_tuple),
                        contains_loop=(source == target),
                    ))
                    if len(paths) >= max_paths:
                        return paths
            except nx.NodeNotFound:
                continue
            except nx.NetworkXError:
                continue

    return paths

def apply_to_session(self, session: aiohttp.ClientSession) -> None:
    """Inject auth into an aiohttp session for Phase 1 crawling."""
    if self.config.method == "cookie":
        session.cookie_jar.update_cookies(
            {self.config.cookie_name: self.config.cookie_value}
        )
    elif self.config.method == "bearer":
        session.headers["Authorization"] = f"Bearer {self.config.bearer_token}"
    elif self.config.method == "header":
        session.headers[self.config.header_name] = self.config.header_value

async def apply_to_context(self, context: BrowserContext, base_url: str) -> None:
    """Inject auth into a Playwright browser context for Phase 2 capture."""
    if self.config.method == "cookie":
        parsed = urlparse(base_url)
        await context.add_cookies([{
            "name": self.config.cookie_name,
            "value": self.config.cookie_value,
            "domain": parsed.hostname or "",
            "path": "/",
        }])
    elif self.config.method == "bearer":
        await context.set_extra_http_headers({
            "Authorization": f"Bearer {self.config.bearer_token}",
        })
    elif self.config.method == "header":
        await context.set_extra_http_headers({
            self.config.header_name: self.config.header_value,
        })

def is_auth_redirect(self, original_url: str, final_url: str) -> bool:
    """Detect if a response redirected to the login page."""
    if not self.config.login_url:
        return False
    login_path = self.config.login_url
    final_parsed = urlparse(final_url)
    original_parsed = urlparse(original_url)
    if final_parsed.path.rstrip("/") == login_path.rstrip("/"):
        return final_parsed.path != original_parsed.path
    return False

async def check_auth_indicator(self, page: Page) -> bool:
    """Check if the auth_indicator selector is present on the page."""
    if not self.config.auth_indicator:
        return False
    try:
        element = await page.query_selector(self.config.auth_indicator)
        return element is not None
    except Exception:
        return False

async def new_context(
    self,
    auth: AuthManager | None = None,
    base_url: str = "",
) -> BrowserContext:
    assert self._browser is not None, "Call start() first"
    context = await self._browser.new_context(
        viewport={
            "width": self._config.viewport_width,
            "height": self._config.viewport_height,
        },
        ignore_https_errors=True,
    )
    if auth and auth.has_auth:
        await auth.apply_to_context(context, base_url)
    return context

def _map_console_level(msg_type: str) -> ConsoleMessageLevel:
    mapping = {
        "log": ConsoleMessageLevel.log,
        "warning": ConsoleMessageLevel.warning,
        "error": ConsoleMessageLevel.error,
        "info": ConsoleMessageLevel.info,
        "debug": ConsoleMessageLevel.debug,
    }
    return mapping.get(msg_type, ConsoleMessageLevel.log)

async def _visit_node(
    pool: BrowserPool,
    node: Node,
    auth_context: AuthContext,
    auth_manager: AuthManager,
    config: WebprobeConfig,
    run_dir: Path,
    semaphore: asyncio.Semaphore,
) -> NodeCapture:
    """Visit a single node with Playwright, capture everything."""
    async with semaphore:
        context = await pool.new_context(
            auth=auth_manager if auth_context == AuthContext.authenticated else None,
            base_url=node.state.url,
        )
        try:
            page = await context.new_page()

            resources: list[Resource] = []
            console_messages: list[ConsoleMessage] = []

            # Resource interception
            async def on_response(response: Response) -> None:
                request = response.request
                res_start = datetime.now(timezone.utc).isoformat()
                try:
                    size = len(await response.body()) if response.ok else None
                except Exception:
                    size = None
                resources.append(Resource(
                    url=request.url,
                    resource_type=_map_resource_type(request.resource_type),
                    status_code=response.status,
                    size_bytes=size,
                    timing=TimingData(
                        started_at=res_start,
                        duration_ms=0,  # Individual resource timing filled via performance API below
                    ),
                    mime_type=response.headers.get("content-type", ""),
                ))

            # Console capture
            def on_console(msg: object) -> None:
                console_messages.append(ConsoleMessage(
                    level=_map_console_level(msg.type),  # type: ignore[attr-defined]
                    text=msg.text,  # type: ignore[attr-defined]
                    url=node.state.url,
                ))

            page.on("response", on_response)
            page.on("console", on_console)

            # Navigate
            nav_start = time.monotonic()
            started_at = datetime.now(timezone.utc).isoformat()
            http_status: int | None = None
            doc_headers: dict[str, str] = {}
            try:
                response = await page.goto(
                    node.state.url,
                    wait_until="networkidle",
                    timeout=config.capture.timeout_ms,
                )
                if response:
                    http_status = response.status
                    doc_headers = dict(response.headers)
            except Exception:
                pass
            nav_duration = (time.monotonic() - nav_start) * 1000

            # Performance timing from browser
            try:
                perf = await page.evaluate("""() => {
                    const t = performance.timing;
                    return {
                        ttfb: t.responseStart - t.navigationStart,
                        domContentLoaded: t.domContentLoadedEventEnd - t.navigationStart,
                        load: t.loadEventEnd - t.navigationStart,
                    };
                }""")
                ttfb_ms = perf.get("ttfb")
                dom_content_loaded_ms = perf.get("domContentLoaded")
                load_event_ms = perf.get("load")
            except Exception:
                ttfb_ms = None
                dom_content_loaded_ms = None
                load_event_ms = None

            # Page content
            try:
                page_title = await page.title()
            except Exception:
                page_title = ""
            try:
                page_text = await page.evaluate("() => document.body?.innerText?.slice(0, 5000) || ''")
            except Exception:
                page_text = ""

            # Outgoing links
            try:
                links = await page.evaluate("""() => {
                    return Array.from(document.querySelectorAll('a[href]'))
                        .map(a => a.href)
                        .filter(h => h && !h.startsWith('javascript:'));
                }""")
            except Exception:
                links = []

            # Cookies
            captured_cookies: list[CookieInfo] = []
            try:
                browser_cookies = await context.cookies()
                for c in browser_cookies:
                    captured_cookies.append(CookieInfo(
                        name=c.get("name", ""),
                        domain=c.get("domain", ""),
                        path=c.get("path", "/"),
                        secure=c.get("secure", False),
                        http_only=c.get("httpOnly", False),
                        same_site=c.get("sameSite", ""),
                    ))
            except Exception:
                pass

            # Forms
            captured_forms: list[FormInfo] = []
            try:
                forms_data = await page.evaluate("""() => {
                    return Array.from(document.querySelectorAll('form')).map(form => {
                        const inputs = Array.from(form.querySelectorAll('input'));
                        const hasPassword = inputs.some(i => i.type === 'password');
                        const hasCsrf = inputs.some(i =>
                            i.name && (i.name.toLowerCase().includes('csrf') ||
                                       i.name.toLowerCase().includes('_token') ||
                                       i.name === '__RequestVerificationToken' ||
                                       i.name === 'authenticity_token')
                        );
                        const autocompleteOff = form.getAttribute('autocomplete') === 'off' ||
                            inputs.some(i => i.type === 'password' && i.getAttribute('autocomplete') === 'off');
                        return {
                            action: form.action || '',
                            method: form.method || 'GET',
                            hasCsrf: hasCsrf,
                            hasPassword: hasPassword,
                            autocompleteOff: autocompleteOff,
                        };
                    });
                }""")
                for f in forms_data:
                    captured_forms.append(FormInfo(
                        action=f.get("action", ""),
                        method=f.get("method", "GET"),
                        has_csrf_token=f.get("hasCsrf", False),
                        has_password_field=f.get("hasPassword", False),
                        autocomplete_off=f.get("autocompleteOff", False),
                    ))
            except Exception:
                pass

            # Screenshot
            screenshot_rel = ""
            if config.capture.screenshot:
                screenshot_rel = _screenshot_path(node.state.url, auth_context)
                screenshot_abs = run_dir / screenshot_rel
                screenshot_abs.parent.mkdir(parents=True, exist_ok=True)
                try:
                    await page.screenshot(path=str(screenshot_abs), full_page=True)
                except Exception:
                    screenshot_rel = ""

            return NodeCapture(
                auth_context=auth_context,
                http_status=http_status,
                timing=TimingData(
                    started_at=started_at,
                    duration_ms=nav_duration,
                    ttfb_ms=ttfb_ms,
                ),
                dom_content_loaded_ms=dom_content_loaded_ms,
                load_event_ms=load_event_ms,
                page_title=page_title,
                page_text=page_text,
                resources=resources,
                console_messages=console_messages,
                outgoing_links=links,
                screenshot_path=screenshot_rel,
                response_headers=ResponseHeaders(raw=doc_headers),
                cookies=captured_cookies,
                forms=captured_forms,
            )
        finally:
            await context.close()

def on_console(msg: object) -> None:
    console_messages.append(ConsoleMessage(
        level=_map_console_level(msg.type),  # type: ignore[attr-defined]
        text=msg.text,  # type: ignore[attr-defined]
        url=node.state.url,
    ))

def load_config(path: str | Path | None = None) -> WebprobeConfig:
    """Load config from explicit path, ./webprobe.yaml, ~/.webprobe/webprobe.yaml, or defaults."""
    if path is not None:
        p = Path(path)
        if p.exists():
            return WebprobeConfig.model_validate(yaml.safe_load(p.read_text()) or {})
        raise FileNotFoundError(f"Config not found: {p}")

    for p in _SEARCH_PATHS:
        if p.exists():
            return WebprobeConfig.model_validate(yaml.safe_load(p.read_text()) or {})

    return WebprobeConfig()

def load_run(run_dir: Path) -> Run:
    """Load a Run from a run directory's report.json."""
    report_path = run_dir / "report.json"
    if not report_path.exists():
        raise FileNotFoundError(f"No report.json in {run_dir}")
    data = json.loads(report_path.read_text())
    return Run.model_validate(data)

def diff_runs(run_a: Run, run_b: Run) -> RunDiff:
    """Compare two runs and produce a diff."""
    if run_a.schema_version != run_b.schema_version:
        raise ValueError(
            f"Schema version mismatch: {run_a.schema_version} vs {run_b.schema_version}"
        )

    nodes_a = set(run_a.graph.nodes.keys())
    nodes_b = set(run_b.graph.nodes.keys())

    # Node set diffs
    nodes_added = sorted(nodes_b - nodes_a)
    nodes_removed = sorted(nodes_a - nodes_b)

    # Edge set diffs (by source+target)
    def edge_key(e: Edge) -> tuple[str, str]:
        return (e.source, e.target)

    edges_a = {edge_key(e): e for e in run_a.graph.edges}
    edges_b = {edge_key(e): e for e in run_b.graph.edges}
    edges_added = [edges_b[k] for k in sorted(set(edges_b) - set(edges_a))]
    edges_removed = [edges_a[k] for k in sorted(set(edges_a) - set(edges_b))]

    # Status changes for nodes in both runs
    status_changes: list[NodeDiff] = []
    for nid in nodes_a & nodes_b:
        node_a = run_a.graph.nodes[nid]
        node_b = run_b.graph.nodes[nid]
        # Compare first capture's HTTP status
        status_a = node_a.captures[0].http_status if node_a.captures else None
        status_b = node_b.captures[0].http_status if node_b.captures else None
        if status_a != status_b:
            status_changes.append(NodeDiff(
                url=nid,
                change="changed",
                details={"http_status": {"before": status_a, "after": status_b}},
            ))

    # Timing changes (> 20% delta)
    timing_changes: list[NodeDiff] = []
    for nid in nodes_a & nodes_b:
        node_a = run_a.graph.nodes[nid]
        node_b = run_b.graph.nodes[nid]
        if node_a.captures and node_b.captures:
            t_a = node_a.captures[0].timing
            t_b = node_b.captures[0].timing
            if t_a and t_b and t_a.duration_ms > 0:
                delta_pct = abs(t_b.duration_ms - t_a.duration_ms) / t_a.duration_ms
                if delta_pct > 0.20:
                    timing_changes.append(NodeDiff(
                        url=nid,
                        change="changed",
                        details={
                            "duration_ms": {
                                "before": t_a.duration_ms,
                                "after": t_b.duration_ms,
                                "delta_pct": round(delta_pct * 100, 1),
                            }
                        },
                    ))

    # Broken link diffs
    def bl_key(bl: BrokenLink) -> tuple[str, str]:
        return (bl.source, bl.target)

    bls_a = set()
    bls_b = set()
    bl_map_a: dict[tuple[str, str], BrokenLink] = {}
    bl_map_b: dict[tuple[str, str], BrokenLink] = {}
    if run_a.analysis:
        for bl in run_a.analysis.broken_links:
            k = bl_key(bl)
            bls_a.add(k)
            bl_map_a[k] = bl
    if run_b.analysis:
        for bl in run_b.analysis.broken_links:
            k = bl_key(bl)
            bls_b.add(k)
            bl_map_b[k] = bl

    new_broken = [bl_map_b[k] for k in sorted(bls_b - bls_a)]
    resolved_broken = [bl_map_a[k] for k in sorted(bls_a - bls_b)]

    # Auth violation diffs
    av_a = set()
    av_b = set()
    av_map_a: dict[str, AuthBoundaryViolation] = {}
    av_map_b: dict[str, AuthBoundaryViolation] = {}
    if run_a.analysis:
        for av in run_a.analysis.auth_violations:
            av_a.add(av.url)
            av_map_a[av.url] = av
    if run_b.analysis:
        for av in run_b.analysis.auth_violations:
            av_b.add(av.url)
            av_map_b[av.url] = av

    new_auth = [av_map_b[k] for k in sorted(av_b - av_a)]
    resolved_auth = [av_map_a[k] for k in sorted(av_a - av_b)]

    return RunDiff(
        run_a_id=run_a.run_id,
        run_b_id=run_b.run_id,
        nodes_added=nodes_added,
        nodes_removed=nodes_removed,
        edges_added=edges_added,
        edges_removed=edges_removed,
        status_changes=status_changes,
        timing_changes=timing_changes,
        new_broken_links=new_broken,
        resolved_broken_links=resolved_broken,
        new_auth_violations=new_auth,
        resolved_auth_violations=resolved_auth,
    )

async def _extract_interactive_elements(page: object) -> str:
    """Extract a summary of interactive elements on the page."""
    try:
        elements = await page.evaluate("""() => {  // type: ignore[attr-defined]
            const els = [];
            const interactives = document.querySelectorAll(
                'a[href], button, input, select, textarea, [role="button"], [role="tab"], ' +
                '[role="link"], [onclick], details > summary, [data-action]'
            );
            const seen = new Set();
            for (const el of interactives) {
                if (els.length >= 40) break;
                const style = getComputedStyle(el);
                if (style.display === 'none' || style.visibility === 'hidden') continue;
                const desc = {
                    tag: el.tagName.toLowerCase(),
                    type: el.type || '',
                    text: (el.innerText || el.value || el.placeholder || '').slice(0, 50),
                    href: el.href || '',
                    name: el.name || '',
                    id: el.id || '',
                    role: el.getAttribute('role') || '',
                };
                const key = JSON.stringify(desc);
                if (seen.has(key)) continue;
                seen.add(key);
                els.push(desc);
            }
            return els;
        }""")
        lines = []
        for el in elements:
            parts = [f"<{el['tag']}"]
            if el.get('type'):
                parts.append(f" type={el['type']}")
            if el.get('id'):
                parts.append(f" id={el['id']}")
            if el.get('name'):
                parts.append(f" name={el['name']}")
            if el.get('role'):
                parts.append(f" role={el['role']}")
            parts.append(">")
            if el.get('text'):
                parts.append(f" \"{el['text']}\"")
            if el.get('href'):
                parts.append(f" href={el['href'][:80]}")
            lines.append("".join(parts))
        return "\n".join(lines) if lines else "(no interactive elements found)"
    except Exception:
        return "(error extracting elements)"

def _path_to_route(filepath: Path, pages_dir: Path, strip_extensions: tuple[str, ...]) -> str:
    """Convert a file path under a pages directory to a URL route."""
    rel = filepath.relative_to(pages_dir)
    parts = list(rel.parts)
    # Strip extension from last part
    if parts:
        name = parts[-1]
        for ext in strip_extensions:
            if name.endswith(ext):
                name = name[: -len(ext)]
                break
        parts[-1] = name

    # index -> /
    if parts and parts[-1] == "index":
        parts = parts[:-1]

    # Convert dynamic segments: [param] -> :param, [...rest] -> *rest
    converted = []
    for p in parts:
        if p.startswith("[...") and p.endswith("]"):
            converted.append(f"*{p[4:-1]}")
        elif p.startswith("[") and p.endswith("]"):
            converted.append(f":{p[1:-1]}")
        else:
            converted.append(p)

    route = "/" + "/".join(converted)
    return route

def detect_astro(project_root: Path) -> list[str]:
    """Detect routes from an Astro project (src/pages/**)."""
    pages_dir = project_root / "src" / "pages"
    if not pages_dir.is_dir():
        # Check for web/ subdirectory (monorepo pattern)
        pages_dir = project_root / "web" / "src" / "pages"
        if not pages_dir.is_dir():
            return []

    routes = []
    extensions = (".astro", ".md", ".mdx", ".html")
    for ext in extensions:
        for f in pages_dir.rglob(f"*{ext}"):
            if f.is_file():
                route = _path_to_route(f, pages_dir, extensions)
                routes.append(route)
    return sorted(set(routes))

def detect_nextjs(project_root: Path) -> list[str]:
    """Detect routes from a Next.js project (app/ or pages/)."""
    routes = []

    # App Router: app/**/page.{tsx,jsx,ts,js}
    app_dir = project_root / "app"
    if app_dir.is_dir():
        for ext in (".tsx", ".jsx", ".ts", ".js"):
            for f in app_dir.rglob(f"page{ext}"):
                if f.is_file():
                    route = _path_to_route(f.parent / "index", app_dir, ("index",))
                    routes.append(route)

    # Pages Router: pages/**/*.{tsx,jsx,ts,js}
    pages_dir = project_root / "pages"
    if pages_dir.is_dir():
        extensions = (".tsx", ".jsx", ".ts", ".js")
        for ext in extensions:
            for f in pages_dir.rglob(f"*{ext}"):
                if f.is_file() and not f.name.startswith("_"):
                    route = _path_to_route(f, pages_dir, extensions)
                    routes.append(route)

    return sorted(set(routes))

def detect_sveltekit(project_root: Path) -> list[str]:
    """Detect routes from a SvelteKit project (src/routes/**/+page.svelte)."""
    routes_dir = project_root / "src" / "routes"
    if not routes_dir.is_dir():
        return []

    routes = []
    for f in routes_dir.rglob("+page.svelte"):
        if f.is_file():
            route = _path_to_route(f.parent / "index", routes_dir, ("index",))
            routes.append(route)
    return sorted(set(routes))

def detect_framework(project_root: Path) -> tuple[str | None, list[str]]:
    """Auto-detect framework and extract routes.

    Returns (framework_name, routes). framework_name is None if not detected.
    """
    root = Path(project_root)

    # Check for Astro
    astro_configs = list(root.glob("astro.config.*")) + list(root.glob("web/astro.config.*"))
    if astro_configs:
        return "astro", detect_astro(root)

    # Check for Next.js
    next_configs = list(root.glob("next.config.*"))
    if next_configs:
        return "nextjs", detect_nextjs(root)

    # Check for SvelteKit
    svelte_configs = list(root.glob("svelte.config.*"))
    if svelte_configs:
        return "sveltekit", detect_sveltekit(root)

    return None, []

def _estimate_cost(model: str, input_tokens: int, output_tokens: int) -> float:
    """Estimate cost in USD. Falls back to mid-range pricing if model unknown."""
    # Try prefix matching
    for key, (inp, out) in _PRICING.items():
        if model.startswith(key) or key.startswith(model):
            return (input_tokens * inp + output_tokens * out) / 1_000_000
    # Default: assume mid-range
    return (input_tokens * 3.0 + output_tokens * 15.0) / 1_000_000

def create_provider(
    provider: str = "anthropic",
    model: str | None = None,
    cost_tracker: CostTracker | None = None,
) -> LLMProvider:
    """Create an LLM provider by name."""
    if provider not in _PROVIDER_DEFAULTS:
        raise ValueError(f"Unknown provider: {provider}. Choose from: {list(_PROVIDER_DEFAULTS)}")
    cls, default_model = _PROVIDER_DEFAULTS[provider]
    return cls(model=model or default_model, cost_tracker=cost_tracker)

def summary(self) -> dict:
    return {
        "total_calls": len(self.calls),
        "total_input_tokens": self.total_input_tokens,
        "total_output_tokens": self.total_output_tokens,
        "total_cost_usd": round(self.total_cost, 4),
        "by_provider": self._by_provider(),
    }

def _by_provider(self) -> dict:
    groups: dict[str, list[LLMCallRecord]] = {}
    for c in self.calls:
        groups.setdefault(c.provider, []).append(c)
    return {
        provider: {
            "calls": len(calls),
            "cost_usd": round(sum(c.estimated_cost_usd for c in calls), 4),
            "tokens": sum(c.input_tokens + c.output_tokens for c in calls),
        }
        for provider, calls in groups.items()
    }

def __init__(self, model: str, cost_tracker: CostTracker | None = None) -> None:
