    self.cost_tracker = cost_tracker or CostTracker()

def is_same_origin(url: str, base_url: str) -> bool:
    """Check if url has same scheme+host+port as base_url."""
    a = urlparse(url)
    b = urlparse(base_url)
    return (a.scheme == b.scheme and a.netloc == b.netloc)

def extract_links(html: str) -> list[tuple[str, str]]:
    """Extract (href, link_text) pairs from HTML."""
    parser = _LinkExtractor()
    try:
        parser.feed(html)
    except Exception:
        pass
    return parser.links

def parse_robots_txt(text: str, base_url: str) -> tuple[list[str], list[str]]:
    """Parse robots.txt. Returns (disallowed_paths, sitemap_urls)."""
    disallowed: list[str] = []
    sitemaps: list[str] = []
    for line in text.splitlines():
        line = line.strip()
        if line.lower().startswith("disallow:"):
            path = line.split(":", 1)[1].strip()
            if path:
                disallowed.append(path)
        elif line.lower().startswith("sitemap:"):
            url = line.split(":", 1)[1].strip()
            # "sitemap:" split on first colon takes "//..." so rejoin
            if not url.startswith("http"):
                url = "sitemap:" + url
                url = url.split(":", 1)[1].strip()
            if url:
                sitemaps.append(url)
    return disallowed, sitemaps

def parse_sitemap(xml_text: str) -> list[str]:
    """Parse a sitemap XML, handling both sitemap indexes and regular sitemaps."""
    urls: list[str] = []
    try:
        root = ET.fromstring(xml_text)
    except ET.ParseError:
        return urls
    # Strip namespace for easier parsing
    ns = ""
    if root.tag.startswith("{"):
        ns = root.tag.split("}")[0] + "}"
    # Sitemap index
    for sm in root.findall(f"{ns}sitemap"):
        loc = sm.find(f"{ns}loc")
        if loc is not None and loc.text:
            urls.append(loc.text.strip())
    # URL set
    for url_elem in root.findall(f"{ns}url"):
        loc = url_elem.find(f"{ns}loc")
        if loc is not None and loc.text:
            urls.append(loc.text.strip())
    return urls

def handle_starttag(self, tag: str, attrs: list[tuple[str, str | None]]) -> None:
    attr_dict = dict(attrs)
    if tag == "a" and "href" in attr_dict:
        self._current_link = attr_dict["href"] or ""
        self._current_text = []
    elif tag == "form" and "action" in attr_dict:
        action = attr_dict["action"] or ""
        if action:
            self.links.append((action, ""))

def handle_data(self, data: str) -> None:
    if self._current_link is not None:
        self._current_text.append(data)

def handle_endtag(self, tag: str) -> None:
    if tag == "a" and self._current_link is not None:
        text = " ".join(self._current_text).strip()
        self.links.append((self._current_link, text))
        self._current_link = None
        self._current_text = []

def load_mask(path: str | Path | None = None) -> MaskConfig:
    """Load mask from YAML file. Returns empty mask if file doesn't exist."""
    if path is None:
        # Check default locations
        for p in [Path("webprobe-mask.yaml"), Path(".webprobe/mask.yaml")]:
            if p.exists():
                path = p
                break
    if path is None:
        return MaskConfig()
    p = Path(path)
    if not p.exists():
        return MaskConfig()
    data = yaml.safe_load(p.read_text()) or {}
    return MaskConfig.model_validate(data)

def apply_mask(findings: list[SecurityFinding], mask: MaskConfig) -> tuple[list[SecurityFinding], list[SecurityFinding]]:
    """Apply mask rules to findings.

    Returns (kept, suppressed) -- both lists for transparency in reports.
    """
    if not mask.rules:
        return findings, []

    kept: list[SecurityFinding] = []
    suppressed: list[SecurityFinding] = []

    for finding in findings:
        masked = False
        for rule in mask.rules:
            url_match = re.search(rule.url_pattern, finding.url) if finding.url else True
            title_match = re.search(rule.title_pattern, finding.title)
            cat_match = (not rule.category) or (rule.category == finding.category.value)
            if url_match and title_match and cat_match:
                masked = True
                break
        if masked:
            suppressed.append(finding)
        else:
            kept.append(finding)

    return kept, suppressed

def _make_run_id() -> str:
    now = datetime.now(timezone.utc)
    return f"{now.strftime('%Y%m%dT%H%M%S')}-{uuid4().hex[:8]}"

def scan_graph(graph: SiteGraph) -> list[SecurityFinding]:
    """Run security scans across all captured nodes. Returns deduplicated findings."""
    all_findings: list[SecurityFinding] = []
    seen: set[tuple[str, str, str]] = set()  # (url, category, title) dedup

    for node in graph.nodes.values():
        for capture in node.captures:
            findings = scan_capture(node.id, capture)
            for f in findings:
                key = (f.url, f.category.value, f.title)
                if key not in seen:
                    seen.add(key)
                    all_findings.append(f)
                    # Also attach to the capture for per-node reporting
                    capture.security_findings.append(f)

    return all_findings

def _relative_luminance(r: int, g: int, b: int) -> float:
    """Calculate relative luminance per WCAG 2.1 (sRGB linearization)."""
    def _linearize(c: int) -> float:
        s = c / 255.0
        return s / 12.92 if s <= 0.04045 else ((s + 0.055) / 1.055) ** 2.4
    return 0.2126 * _linearize(r) + 0.7152 * _linearize(g) + 0.0722 * _linearize(b)

def check_wcag_aa(ratio: float, large_text: bool = False) -> bool:
    """WCAG AA: 4.5:1 for normal text, 3:1 for large text (>=18pt or >=14pt bold)."""
    return ratio >= (3.0 if large_text else 4.5)

def check_wcag_aaa(ratio: float, large_text: bool = False) -> bool:
    """WCAG AAA: 7:1 for normal text, 4.5:1 for large text."""
    return ratio >= (4.5 if large_text else 7.0)

def _parse_rgb(css_color: str) -> tuple[int, int, int] | None:
    """Parse rgb(r,g,b) or rgba(r,g,b,a) to (r,g,b). Returns None if unparseable."""
    css_color = css_color.strip()
    if css_color.startswith("rgb"):
        # Extract numbers
        import re
        nums = re.findall(r"[\d.]+", css_color)
        if len(nums) >= 3:
            return (int(float(nums[0])), int(float(nums[1])), int(float(nums[2])))
    elif css_color.startswith("#"):
        hex_str = css_color[1:]
        if len(hex_str) == 3:
            hex_str = "".join(c * 2 for c in hex_str)
        if len(hex_str) == 6:
            return (int(hex_str[0:2], 16), int(hex_str[2:4], 16), int(hex_str[4:6], 16))
    return None

def _linearize(c: int) -> float:
    s = c / 255.0
    return s / 12.92 if s <= 0.04045 else ((s + 0.055) / 1.055) ** 2.4
